import { useState, useEffect, useMemo, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useNavigate } from "react-router-dom";
import {
  LayoutDashboard,
  ShoppingCart,
  Users,
  Package,
  BarChart3,
  Settings,
  User,
  LogOut,
} from "lucide-react";

import { adminDashboardDesign as design } from "../../design/adminDashboardDesign";

const menuItems = [
  { name: "Dashboard", icon: LayoutDashboard },
  { name: "Products", icon: Package },
  { name: "Orders", icon: ShoppingCart },
  { name: "Users", icon: Users },
  { name: "Analytics", icon: BarChart3 },
  { name: "Settings", icon: Settings },
];

const AdminDashboard = () => {
  const navigate = useNavigate();
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo"));
  const [search, setSearch] = useState("");
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef(null);

  // Close dropdown when click outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Get initials
  const getInitials = (name) => {
    if (!name) return "";
    const words = name.trim().split(" ");
    if (words.length === 1) return words[0][0].toUpperCase();
    return (
      words[0][0].toUpperCase() +
      words[1][0].toUpperCase()
    );
  };

  // Filter sidebar
  const filteredMenu = useMemo(() => {
    return menuItems.filter((item) =>
      item.name.toLowerCase().includes(search.toLowerCase())
    );
  }, [search]);

  // Logout
  const handleLogout = () => {
    localStorage.removeItem("adminInfo");
    localStorage.removeItem("token");
    navigate("/admin/login");
  };

  return (
    <div className={design.layout.wrapper}>

      {/* 🔥 TOP NAVBAR */}
      <div className={design.layout.navbar}>

        <h1 className="text-xl font-semibold text-gray-800">
          Admin Panel
        </h1>

        <input
          type="text"
          placeholder="Search menu..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className={design.colors.input}
        />

        {/* Avatar + Dropdown */}
        <div className="relative" ref={dropdownRef}>
          <div
            onClick={() => setDropdownOpen(!dropdownOpen)}
            className="w-10 h-10 rounded-full bg-indigo-600 text-white flex items-center justify-center font-semibold cursor-pointer"
          >
            {getInitials(adminInfo?.name)}
          </div>

          <AnimatePresence>
            {dropdownOpen && (
              <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 10 }}
                className="absolute right-0 mt-3 w-64 bg-white shadow-lg rounded-lg p-4 z-50"
              >
                <div className="border-b pb-3 mb-3">
                  <p className="font-semibold text-gray-800">
                    {adminInfo?.name}
                  </p>
                  <p className="text-sm text-gray-500">
                    {adminInfo?.email}
                  </p>
                </div>

                <div
                  onClick={() => navigate("/admin/profile")}
                  className="flex items-center gap-2 p-2 rounded-md hover:bg-gray-100 cursor-pointer text-sm"
                >
                  <User size={16} />
                  Profile
                </div>

                <div
                  onClick={handleLogout}
                  className="flex items-center gap-2 p-2 rounded-md hover:bg-gray-100 cursor-pointer text-sm text-red-500"
                >
                  <LogOut size={16} />
                  Logout
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>

      {/* 🔥 BODY */}
      <div className={design.layout.body}>

        {/* Sidebar */}
        <aside className={`${design.colors.sidebar} ${design.layout.sidebar}`}>
          <nav className="space-y-2">
            {filteredMenu.length > 0 ? (
              filteredMenu.map((item, index) => {
                const Icon = item.icon;
                return (
                  <div
                    key={index}
                    className={`${design.layout.navItem} ${design.colors.hover}`}
                  >
                    <Icon size={18} />
                    {item.name}
                  </div>
                );
              })
            ) : (
              <p className="text-sm text-gray-500">No results</p>
            )}
          </nav>
        </aside>

        {/* Content */}
        <div className={design.layout.content}>
          <h2 className="text-2xl font-bold mb-4">
            Welcome Back 👋
          </h2>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
